import React, { useState } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faBars, faXmark } from '@fortawesome/free-solid-svg-icons';
//import './Navbar.css';
import cls from './Navbar.module.scss';
import { Link } from 'react-router-dom';
import { isMobile } from 'react-device-detect';

function Navbar() {
	const [nav, setNav] = useState(false);

	const openNav = () => {
		setNav(!nav);
	};

	return (
		<div className={cls.navbarsection} style={{height: isMobile ? '100px' : '160px' }}>

			<ADPLOGO />
			{/* Desktop */}
			<ul className={cls.navbaritems} style={{ display: isMobile ? 'none' : 'flex' }}>
				<li>
					<a href="#/flowhero" className={cls.navbarlinks}>
						{'FLOWHERO™'}
					</a>
				</li>
				<li>
					<a onClick={() => window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' })}className={cls.navbarlinks} style={{ cursor: 'pointer', fontSize: '20px' }}>
						{'ABOUT'}
					</a>
				</li>
			</ul>

			{/* Mobile */}
			<div className={`mobile-navbar ${nav ? 'open-nav' : ''}`}>
				<div onClick={openNav} className="mobile-navbar-close">
					<FontAwesomeIcon icon={faXmark} className="hamb-icon" />
				</div>

				<ul className={cls.mobilenavbarlinks}>
					<li>
						<Link onClick={openNav} to="/">
							{'HOME'}
						</Link>
					</li>

					<li>
						<a onClick={openNav} href="/#/flowhero">
							{'FLOWHERO™'}
						</a>
					</li>
				</ul>
			</div>

			{/* Hamburger Icon */}
			<div className="mobile-nav" style={{ display: isMobile ? 'block' : 'none' }}>
				<FontAwesomeIcon icon={faBars} onClick={openNav} className="hamb-icon" />
			</div>
		</div>
	);
}

export default Navbar;

export const ADPLOGO = () => {
	return <div style={{ display: 'flex', justifyItems: 'center', alignItems: 'center', alignContent: 'center' }}>
		{!isMobile && <div className={cls.containerNav}>
			<div className={cls.circleNav}></div>
			<div className={cls.smallcircleNav}></div>
			<div className={cls.smallercircleNav}></div>
			<div className={cls.smallestcircleNav}></div>
		</div>}

		<div className={cls.navbartitle} style={{ marginBottom: '20px' }}>
			<Link to="/" style={{ fontSize: isMobile ? '20px' : '30px', fontWeight: 'normal', marginLeft: isMobile ? '0' : '1px' }}>{'ADPGxSOFTWARE SOLUTIONS'}</Link>
		</div>
	</div>;
}


